INSERT OR REPLACE INTO sh_weekly_summary(period_key,period_start,period_end,sample_count,reliable_sample_count,listener_avg,listener_min,listener_max,stream_start,stream_end,stream_growth,member_start,member_end,member_growth,likes_max,distinct_tracks,primary_host,quality_score,quality_flags,updated_at)
SELECT period_key,period_start,period_end,sample_count,reliable_sample_count,listener_avg,listener_min,listener_max,stream_start,stream_end,CASE WHEN stream_start IS NOT NULL AND stream_end>=stream_start THEN stream_end-stream_start END,member_start,member_end,CASE WHEN member_start IS NOT NULL AND member_end IS NOT NULL THEN member_end-member_start END,likes_max,NULL,NULL,1,'["utc_rebuild"]',unixepoch('now')*1000 FROM sh_weekly_metric_utc WHERE sample_count>0;
